import java.util.Stack;

public class ParenthesesCounter {
    public static void main(String[] args) {
        String input = "((())())"; // Your input string goes here
        System.out.println("Number of valid parentheses: " + countValidParentheses(input));
    }

    public static int countValidParentheses(String s) {
        Stack<Character> stack = new Stack<>();
        int balance = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') {
                stack.push(c);
                balance++;
            } else if (c == ')') {
                if (!stack.isEmpty()) {
                    stack.pop();
                    balance--;
                } else {
                    // Found a closing parenthesis without a matching opening one
                    return -1; // Invalid input!
                }
            }
        }
        return balance; // This will be 0 for valid parentheses
    }
}
```

